mapper.select:
SELECT cc.case_id, cc.student_id, su.real_name as student_name, cc.counselor_id, cu.real_name as counselor_name, cc.case_title, cc.case_status, cc.problem_type, cc.case_description, cc.start_date, cc.close_date, cc.total_sessions, cc.created_at, cc.updated_at FROM consultation_case cc LEFT JOIN user su ON cc.student_id = su.user_id LEFT JOIN counselor_info ci ON cc.counselor_id = ci.counselor_id LEFT JOIN user cu ON ci.counselor_id = cu.user_id
AND cc.counselor_id = #{query.counselorId}
AND cc.student_id = #{query.studentId}
AND cc.case_status = #{query.caseStatus}
AND cc.problem_type = #{query.problemType}
ORDER BY cc.created_at DESC

SELECT case_status as status, COUNT(*) as count FROM consultation_case
AND counselor_id = #{counselorId}
GROUP BY case_status
